/* =====================================================================
   AUTO-LOCK ON LOAD
   ---------------------------------------------------------------------
   Want the Secure Input Section to already be ON (checked, password-
   protected) the moment index.html is opened, with no extra steps?
   Set it up right here:

     const DEFAULT_APP_STATE = {
       locked: true,
       password: 'yourPassword',
       passwordHint: 'a hint that helps only you remember it'
     };

   This only applies the very first time this file is opened in a given
   browser (i.e. before anything has been saved yet). From that point
   on, the lock/unlock state you actually leave the app in is what
   reopens next time — exactly like the datasets above. So if you ship
   the file pre-locked like this, anyone opening it for the first time
   will immediately see the checkbox already ticked, the Input section
   read-only, and the Active Dataset card blurred behind the lock
   screen, and they will need the password you set here to get in.

   The "Download Full App Data" button in Settings → Active Dataset
   outputs an updated version of this block reflecting whatever
   password/lock state is currently saved in this browser, so you can
   paste it back in here later and make it the new permanent default. */
const DEFAULT_APP_STATE = {
  locked: true,
  password: 'NoCodeView@000',
  passwordHint: 'NCV@0'
};

/* =====================================================================
   APP VERSION
   ---------------------------------------------------------------------
   Shown in the small footer strip at the bottom of every page. Format
   is ddmmyyyy_X.Y (date_versionNumber). Change this any time you want
   — or just use the "Download Full App Data" button in Settings, which
   bumps this by +0.1 and stamps today's date automatically every time
   you download, so you never have to think about it. */
const APP_VERSION = '13072026_0650_FINAL';